const payload = $('Normalize payload').first().json;
const apiKey = $env.OPENAI_API_KEY;
if (!apiKey) {
  throw new Error('Define OPENAI_API_KEY en Variables de entorno de n8n');
}

const system = 'Eres el asistente del administrador de Jose Dev (ingeniería full stack). Representa sus intereses: calidad técnica, plazos realistas, encaje del proyecto, stack y servicios. Responde en el idioma del usuario, de forma concisa y profesional. Si piden reunión, llamada, videollamada o información muy extensa que requiera hablar en directo, responde con showMeetingPicker true. Devuelve SOLO JSON válido sin markdown: {"reply":"...","showMeetingPicker":boolean}';

const response = await fetch('https://api.openai.com/v1/chat/completions', {
  method: 'POST',
  headers: {
    Authorization: `Bearer ${apiKey}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    model: 'gpt-4o-mini',
    temperature: 0.4,
    messages: [
      { role: 'system', content: system },
      { role: 'user', content: `${payload.text}\n\nEmail visitante: ${payload.userEmail}` },
    ],
  }),
});

const data = await response.json();
if (!response.ok) {
  throw new Error(data?.error?.message || `OpenAI HTTP ${response.status}`);
}

const rawText = data.choices?.[0]?.message?.content ?? '';
let parsed;
try {
  const cleaned = String(rawText).replace(/^```json\n?|```$/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch {
  parsed = {
    reply: String(rawText).slice(0, 4000) || 'Gracias por tu mensaje.',
    showMeetingPicker: /reuni[oó]n|meet|llamada|agendar|videollamada/i.test(payload.text || ''),
  };
}

return [{
  json: {
    conversationId: payload.conversationId,
    reply: String(parsed.reply || 'Gracias por tu mensaje.'),
    showMeetingPicker: Boolean(parsed.showMeetingPicker),
    callbackUrl: payload.callbackUrl,
  },
}];
